configure(consumer: MiddlewareConsumer) {
  consumer
    .apply((req, res, next) => res.end(MIDDLEWARE_VALUE))
    .forRoutes({ path: MIDDLEWARE_VALUE, method: RequestMethod.GET })
    .apply((req, res, next) => res.status(201).end(MIDDLEWARE_VALUE))
    .forRoutes({ path: MIDDLEWARE_VALUE, method: RequestMethod.POST })
    .apply((req, res, next) => res.end(MIDDLEWARE_PARAM_VALUE))
    .forRoutes({
      path: MIDDLEWARE_VALUE + '/*path',
      method: RequestMethod.GET,
    })
    .apply((req, res, next) => res.status(201).end(MIDDLEWARE_PARAM_VALUE))
    .forRoutes({
      path: MIDDLEWARE_VALUE + '/*path',
      method: RequestMethod.POST,
    })
    .apply((req, res, next) => {
      req.extras = { data: 'Data attached in middleware' };
      next();
    })
    .forRoutes({ path: '*path', method: RequestMethod.GET })
    .apply((req, res, next) => {
      req.middlewareParams = req.params;
      next();
    })
    .forRoutes({ path: '*path', method: RequestMethod.GET })
    .apply((req, res, next) => {
      this.count += 1;
      req.count = this.count;
      next();
    })
    .forRoutes('*path');
}

function parseArgs(argv: string[]): Args {
  const args: Args = { ...DEFAULTS };

  for (let i = 0; i < argv.length; i++) {
    const token = argv[i];

    if (token === '--verbose' || token === '-v') {
      args.verbose = true;
      continue;
    }

    if (token === '--connections' || token === '-c') {
      args.connections = parseNumber(argv[++i], args.connections);
      continue;
    }

    if (token === '--duration' || token === '-d') {
      args.duration = parseNumber(argv[++i], args.duration);
      continue;
    }

    if (token === '--pipelining' || token === '-p') {
      args.pipelining = parseNumber(argv[++i], args.pipelining);
      continue;
    }

    if (token === '--port') {
      args.port = parseNumber(argv[++i], args.port);
      continue;
    }

    if (token === '--path') {
      args.path = argv[++i] ?? args.path;
      continue;
    }

    if (token === '--help' || token === '-h') {
      printHelpAndExit(0);
    }
  }

  return args;
}

protected printMessages(
  messages: unknown[],
  context = '',
  logLevel: LogLevel = 'log',
  writeStreamType?: 'stdout' | 'stderr',
  errorStack?: unknown,
) {
  messages.forEach(message => {
    if (this.options.json) {
      this.printAsJson(message, {
        context,
        logLevel,
        writeStreamType,
        errorStack,
      });
      return;
    }
    const pidMessage = this.formatPid(process.pid);
    const contextMessage = this.formatContext(context);
    const timestampDiff = this.updateAndGetTimestampDiff();
    const formattedLogLevel = logLevel.toUpperCase().padStart(7, ' ');
    const formattedMessage = this.formatMessage(
      logLevel,
      message,
      pidMessage,
      formattedLogLevel,
      contextMessage,
      timestampDiff,
    );

    if (this.options.forceConsole) {
      if (writeStreamType === 'stderr') {
        console.error(formattedMessage.trim());
      } else {
        console.log(formattedMessage.trim());
      }
    } else {
      process[writeStreamType ?? 'stdout'].write(formattedMessage);
    }
  });
}

protected getInspectOptions() {
  let breakLength = this.options.breakLength;
  if (typeof breakLength === 'undefined') {
    breakLength = this.options.colors
      ? this.options.compact
        ? Infinity
        : undefined
      : this.options.compact === false
        ? undefined
        : Infinity; // default breakLength to Infinity if inline is not set and colors is false
  }

  const inspectOptions: InspectOptions = {
    depth: this.options.depth ?? DEFAULT_DEPTH,
    sorted: this.options.sorted,
    showHidden: this.options.showHidden,
    compact: this.options.compact ?? (this.options.json ? true : false),
    colors: this.options.colors,
    breakLength,
  };

  if (typeof this.options.maxArrayLength !== 'undefined') {
    inspectOptions.maxArrayLength = this.options.maxArrayLength;
  }
  if (typeof this.options.maxStringLength !== 'undefined') {
    inspectOptions.maxStringLength = this.options.maxStringLength;
  }

  return inspectOptions;
}

export function AnyFilesInterceptor(
  localOptions?: MulterOptions,
): Type<NestInterceptor> {
  class MixinInterceptor implements NestInterceptor {
    protected multer: MulterInstance;

    constructor(
      @Optional()
      @Inject(MULTER_MODULE_OPTIONS)
      options: MulterModuleOptions = {},
    ) {
      this.multer = (multer as any)({
        ...options,
        ...localOptions,
      });
    }

    async intercept(
      context: ExecutionContext,
      next: CallHandler,
    ): Promise<Observable<any>> {
      const ctx = context.switchToHttp();

      await new Promise<void>((resolve, reject) =>
        this.multer.any()(ctx.getRequest(), ctx.getResponse(), (err: any) => {
          if (err) {
            const error = transformException(err);
            return reject(error);
          }
          resolve();
        }),
      );
      return next.handle();
    }
  }
  const Interceptor = mixin(MixinInterceptor);
  return Interceptor;
}

